// n8n Code 节点专用代码
// 功能：将上游所有数据原样传递，并为每个item添加图片数量统计
// 返回：所有输入项，每个项的JSON中都增加了imageCount字段
// ================================================

// 1. 获取所有输入项
const allInputItems = $input.all();

// 2. 遍历每一个输入项，为其添加图片计数
const processedItems = allInputItems.map(item => {
  // 计算当前项的 binary 对象中的图片数量
  const imageCount = item.binary ? Object.keys(item.binary).length : 0;

  // 创建一个新的输出项，保留所有原始数据，并添加图片计数
  return {
    json: {
      // 展开原始 JSON 数据
      ...item.json,
      // 添加图片计数字段
      imageCount: imageCount,
      // (可选) 添加一个布尔值，方便判断是否有图片
      hasImages: imageCount > 0
    },
    // 保留原始的 binary 数据
    binary: item.binary
  };
});

// 3. 返回处理后的所有项
return processedItems;

